import React, { useState } from 'react';
import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';
import { Tabs, Card, Badge, Alert, EmptyState } from '../ui';
import { Table2, BarChart2, Brain, Code2, ChevronDown, ChevronUp, Sparkles, Layers } from 'lucide-react';
import './ResultsPanel.css';
import { genuiAPI } from '../../services/api';
import AiFunctionsPanel from './AiFunctionsPanel';

const COLORS = ['#3b82f6','#22c55e','#f59e0b','#a855f7','#14b8a6','#ef4444','#f97316','#06b6d4'];

/* ── Helpers ─────────────────────────────────────────────────── */
function safeStr(v) { return v == null ? '' : String(v); }

function normalizeTopValues(tv) {
  if (!tv) return [];
  if (Array.isArray(tv)) {
    return tv.map(item =>
      Array.isArray(item) ? [safeStr(item[0]), safeStr(item[1])] :
      typeof item === 'object' ? [safeStr(item.value ?? item.val ?? item.name ?? ''), safeStr(item.count ?? item.cnt ?? '')] :
      [safeStr(item), '']
    );
  }
  if (typeof tv === 'object') return Object.entries(tv).map(([k,v]) => [safeStr(k), safeStr(v)]);
  return [];
}

function normalizeCols(profile) {
  if (!profile) return [];
  const raw = profile.columns ?? profile.column_profiles ?? profile.col_profiles ?? [];
  if (Array.isArray(raw)) return raw;
  if (typeof raw === 'object') return Object.entries(raw).map(([name, stats]) => ({ name, ...stats }));
  return [];
}

/* ── DataTable ────────────────────────────────────────────────── */
function DataTable({ data, columns }) {
  if (!data?.length) return <EmptyState icon={<Table2 size={22}/>} title="No data returned" />;
  const cols = columns?.length ? columns : Object.keys(data[0]);
  return (
    <div className="data-table-wrap">
      <div className="data-table-meta">{data.length} row{data.length !== 1 ? 's' : ''} / {cols.length} col{cols.length !== 1 ? 's' : ''}</div>
      <div className="data-table-scroll">
        <table className="data-table">
          <thead><tr>{cols.map(c => <th key={c}>{c}</th>)}</tr></thead>
          <tbody>
            {data.map((row, i) => (
              <tr key={i}>
                {cols.map(c => (
                  <td key={c}>
                    <span className={typeof row[c] === 'number' ? 'cell-num' : ''}>
                      {row[c] == null ? <span className="cell-null">null</span>
                        : typeof row[c] === 'object' ? JSON.stringify(row[c])
                        : String(row[c])}
                    </span>
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

/* ── ChartPanel (Collage View) ───────────────────────────────── */
function ChartPanel({ data, viz, summary }) {
  const allCols  = data?.length ? Object.keys(data[0]) : [];
  const numCols  = allCols.filter(k => data[0] && typeof data[0][k] === 'number');
  const textCols = allCols.filter(k => data[0] && typeof data[0][k] !== 'number');

  const [xCol, setXCol]       = useState(viz?.x_col || textCols[0] || allCols[0] || '');
  const [yCols, setYCols]     = useState(viz?.y_cols || numCols.slice(0, 2) || []);
  const [focused, setFocused] = useState(null);
  const [animate, setAnimate] = useState(true);

  const colKey = allCols.join(',');
  React.useEffect(() => {
    setXCol(viz?.x_col || textCols[0] || allCols[0] || '');
    setYCols(viz?.y_cols || numCols.slice(0, 2) || []);
    setAnimate(true);
    setTimeout(() => setAnimate(false), 1000);
  }, [colKey]); // eslint-disable-line

  if (!data?.length) return (
    <EmptyState icon={<BarChart2 size={22}/>} title="No chart available" />
  );

  const activeY = yCols.length ? yCols : numCols.slice(0, 1);

  // ── Gradient colors ──────────────────────────────────────────
  const CHART_COLORS = [
    '#6366f1', '#22c55e', '#f59e0b', '#14b8a6',
    '#a855f7', '#ef4444', '#f97316', '#06b6d4'
  ];

  const CARD_STYLES = [
    { border: '#6366f130', bg: '#6366f108', accent: '#6366f1' },
    { border: '#22c55e30', bg: '#22c55e08', accent: '#22c55e' },
    { border: '#f59e0b30', bg: '#f59e0b08', accent: '#f59e0b' },
    { border: '#14b8a630', bg: '#14b8a608', accent: '#14b8a6' },
  ];

  // ── Download chart as PNG ────────────────────────────────────
  const downloadChart = (chartId) => {
    const container = document.getElementById(`chart-container-${chartId}`);
    if (!container) return;
    const svg = container.querySelector('svg');
    if (!svg) return;
    const svgData = new XMLSerializer().serializeToString(svg);
    const canvas  = document.createElement('canvas');
    const ctx     = canvas.getContext('2d');
    const img     = new Image();
    canvas.width  = svg.clientWidth  || 600;
    canvas.height = svg.clientHeight || 300;
    img.onload = () => {
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(img, 0, 0);
      const a = document.createElement('a');
      a.download = `chart-${chartId}.png`;
      a.href = canvas.toDataURL('image/png');
      a.click();
    };
    img.src = 'data:image/svg+xml;base64,' + btoa(unescape(encodeURIComponent(svgData)));
  };

  // ── Chart renderers ──────────────────────────────────────────
  const renderBar = () => (
    <BarChart data={data} margin={{top:10, right:10, left:0, bottom:5}}>
      <defs>
        {activeY.map((k, i) => (
          <linearGradient key={k} id={`barGrad${i}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={CHART_COLORS[i]} stopOpacity={0.9}/>
            <stop offset="100%" stopColor={CHART_COLORS[i]} stopOpacity={0.5}/>
          </linearGradient>
        ))}
      </defs>
      <CartesianGrid strokeDasharray="3 3" stroke="#f1f3f7" vertical={false}/>
      <XAxis dataKey={xCol} tick={{fontSize:10, fill:'#6b7591'}}
        axisLine={{stroke:'#e5e7eb'}} tickLine={false}/>
      <YAxis tick={{fontSize:10, fill:'#6b7591'}} axisLine={false} tickLine={false}
        tickFormatter={v => Number(v).toLocaleString()}/>
      <Tooltip
        contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}
        formatter={v => [Number(v).toLocaleString()]}/>
      <Legend wrapperStyle={{fontSize:11}}/>
      {activeY.map((k, i) => (
        <Bar key={k} dataKey={k} fill={`url(#barGrad${i})`}
          radius={[6,6,0,0]} maxBarSize={52} isAnimationActive={animate}/>
      ))}
    </BarChart>
  );

  const renderLine = () => (
    <LineChart data={data} margin={{top:10, right:10, left:0, bottom:5}}>
      <CartesianGrid strokeDasharray="3 3" stroke="#f1f3f7"/>
      <XAxis dataKey={xCol} tick={{fontSize:10, fill:'#6b7591'}}
        axisLine={{stroke:'#e5e7eb'}} tickLine={false}/>
      <YAxis tick={{fontSize:10, fill:'#6b7591'}} axisLine={false} tickLine={false}
        tickFormatter={v => Number(v).toLocaleString()}/>
      <Tooltip
        contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}
        formatter={v => [Number(v).toLocaleString()]}/>
      <Legend wrapperStyle={{fontSize:11}}/>
      {activeY.map((k, i) => (
        <Line key={k} type="monotone" dataKey={k} stroke={CHART_COLORS[i]}
          strokeWidth={2.5} dot={{r:3, fill:CHART_COLORS[i]}}
          activeDot={{r:5}} isAnimationActive={animate}/>
      ))}
    </LineChart>
  );

  const renderPie = () => (
    <PieChart margin={{top:10, right:10, left:10, bottom:5}}>
      <Pie data={data} dataKey={activeY[0] || numCols[0]} nameKey={xCol}
        cx="50%" cy="45%" outerRadius={85} innerRadius={30}
        paddingAngle={3} isAnimationActive={animate}
        label={({name, percent}) =>
          percent > 0.05 ? `${(percent*100).toFixed(0)}%` : ''
        }
        labelLine={false}>
        {data.map((_, i) => (
          <Cell key={i} fill={CHART_COLORS[i % CHART_COLORS.length]}
            stroke="white" strokeWidth={2}/>
        ))}
      </Pie>
      <Tooltip
        contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}
        formatter={v => [Number(v).toLocaleString()]}/>
      <Legend wrapperStyle={{fontSize:11}}/>
    </PieChart>
  );

  const renderHBar = () => (
    <BarChart data={data} layout="vertical" margin={{top:10, right:10, left:0, bottom:5}}>
      <defs>
        {activeY.map((k, i) => (
          <linearGradient key={k} id={`hbarGrad${i}`} x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor={CHART_COLORS[i]} stopOpacity={0.5}/>
            <stop offset="100%" stopColor={CHART_COLORS[i]} stopOpacity={0.9}/>
          </linearGradient>
        ))}
      </defs>
      <CartesianGrid strokeDasharray="3 3" stroke="#f1f3f7" horizontal={false}/>
      <XAxis type="number" tick={{fontSize:10, fill:'#6b7591'}} axisLine={false}
        tickLine={false} tickFormatter={v => Number(v).toLocaleString()}/>
      <YAxis type="category" dataKey={xCol} tick={{fontSize:10, fill:'#6b7591'}}
        axisLine={{stroke:'#e5e7eb'}} tickLine={false} width={100}/>
      <Tooltip
        contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}
        formatter={v => [Number(v).toLocaleString()]}/>
      <Legend wrapperStyle={{fontSize:11}}/>
      {activeY.map((k, i) => (
        <Bar key={k} dataKey={k} fill={`url(#hbarGrad${i})`}
          radius={[0,6,6,0]} maxBarSize={32} isAnimationActive={animate}/>
      ))}
    </BarChart>
  );

  // ── Stats card ───────────────────────────────────────────────
  const renderStats = () => {
    const stats = numCols.slice(0, 4).map((col, i) => {
      const vals = data.map(r => Number(r[col])).filter(v => !isNaN(v));
      const total = vals.reduce((a,b) => a+b, 0);
      const avg   = vals.length ? total / vals.length : 0;
      return {
        col, color: CHART_COLORS[i],
        bg: CARD_STYLES[i % CARD_STYLES.length].bg,
        border: CARD_STYLES[i % CARD_STYLES.length].border,
        total, avg,
        max: vals.length ? Math.max(...vals) : 0,
        min: vals.length ? Math.min(...vals) : 0,
      };
    });

    if (!stats.length) return (
      <div style={{padding:24, textAlign:'center', color:'#9ca3af', fontSize:13}}>
        No numeric columns to summarize
      </div>
    );

    return (
      <div style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${Math.min(stats.length, 4)}, 1fr)`,
        gap: 12, padding: 16
      }}>
        {stats.map(s => (
          <div key={s.col} style={{
            background: s.bg,
            border: `1.5px solid ${s.border}`,
            borderRadius: 12, padding: 16,
            transition: 'transform 0.2s, box-shadow 0.2s',
          }}
            onMouseEnter={e => {
              e.currentTarget.style.transform = 'translateY(-2px)';
              e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.08)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = 'none';
            }}
          >
            <div style={{
              fontSize: 10, color: s.color, fontWeight: 700,
              marginBottom: 12, textTransform: 'uppercase',
              letterSpacing: '0.08em', overflow: 'hidden',
              textOverflow: 'ellipsis', whiteSpace: 'nowrap'
            }}>
              {s.col}
            </div>
            <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:10}}>
              {[
                {label:'Total', value: s.total, icon:'Σ'},
                {label:'Avg',   value: s.avg,   icon:'∅'},
                {label:'Max',   value: s.max,   icon:'↑'},
                {label:'Min',   value: s.min,   icon:'↓'},
              ].map(({label, value, icon}) => (
                <div key={label} style={{
                  background: 'rgba(255,255,255,0.7)',
                  borderRadius: 8, padding: '8px 10px'
                }}>
                  <div style={{fontSize:10, color:'#9ca3af', marginBottom:2}}>
                    {icon} {label}
                  </div>
                  <div style={{fontSize:15, fontWeight:700, color: s.color}}>
                    {Number(value).toLocaleString(undefined, {maximumFractionDigits:1})}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    );
  };

  const charts = [
    { id:'bar',  label:'Bar Chart',      icon:'▊', render: renderBar  },
    { id:'line', label:'Line Chart',     icon:'∿', render: renderLine },
    { id:'pie',  label:'Pie Chart',      icon:'◔', render: renderPie  },
    { id:'hbar', label:'Horizontal Bar', icon:'▬', render: renderHBar },
  ];

  return (
    <div className="chart-panel">

      {/* ── Controls ── */}
      <div className="chart-controls" style={{
        marginBottom: 16, padding: '10px 14px',
        background: '#f9fafb', borderRadius: 10,
        border: '1px solid #f3f4f6'
      }}>
        <div className="chart-control-group">
          <label className="chart-ctrl-label">X Axis</label>
          <select className="chart-select" value={xCol}
            onChange={e => setXCol(e.target.value)}>
            {allCols.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        {numCols.length > 0 && (
          <div className="chart-control-group">
            <label className="chart-ctrl-label">Y Columns</label>
            <div className="chart-y-checks">
              {numCols.map(c => (
                <label key={c} className="chart-y-check">
                  <input type="checkbox" checked={yCols.includes(c)}
                    onChange={() => setYCols(prev =>
                      prev.includes(c) ? prev.filter(x => x !== c) : [...prev, c]
                    )}
                  />
                  <span>{c}</span>
                </label>
              ))}
            </div>
          </div>
        )}
        {focused && (
          <button className="chart-type-btn active"
            style={{marginLeft:'auto'}}
            onClick={() => setFocused(null)}>
            ⊞ Show All Charts
          </button>
        )}
      </div>

      {summary && (
        <div style={{
          background: 'linear-gradient(135deg, #eef2ff, #f5f3ff)',
          border: '1px solid #e0e7ff', borderRadius: 10,
          padding: '10px 16px', marginBottom: 14,
          fontSize: 13, color: '#4338ca', fontStyle: 'italic'
        }}>
          💡 {summary}
        </div>
      )}

      {/* ── Focused single chart ── */}
      {focused ? (
        <div style={{
          background:'#fff', borderRadius:12,
          border:'1.5px solid #e5e7eb',
          boxShadow:'0 4px 16px rgba(0,0,0,0.06)',
          padding: 20
        }}>
          <div style={{
            display:'flex', justifyContent:'space-between',
            alignItems:'center', marginBottom:16
          }}>
            <span style={{fontSize:14, fontWeight:700, color:'#111827'}}>
              {charts.find(c => c.id === focused)?.icon}{' '}
              {charts.find(c => c.id === focused)?.label}
            </span>
            <div style={{display:'flex', gap:8}}>
              <button onClick={() => downloadChart(focused)} style={{
                fontSize:11, color:'#6b7280', background:'#f3f4f6',
                border:'none', borderRadius:6, padding:'5px 12px',
                cursor:'pointer', fontWeight:600
              }}>
                ⬇ Download PNG
              </button>
              <button onClick={() => setFocused(null)} style={{
                fontSize:11, color:'#6366f1', background:'#eef2ff',
                border:'none', borderRadius:6, padding:'5px 12px',
                cursor:'pointer', fontWeight:600
              }}>
                ← Back to collage
              </button>
            </div>
          </div>
          <div id={`chart-container-${focused}`}>
            <ResponsiveContainer width="100%" height={420}>
              {charts.find(c => c.id === focused)?.render()}
            </ResponsiveContainer>
          </div>
        </div>
      ) : (
        <div>
          {/* ── 2x2 Collage grid ── */}
          <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:14}}>
            {charts.map((chart, idx) => (
              <div key={chart.id}
                id={`chart-container-${chart.id}`}
                style={{
                  background:'#fff', borderRadius:12,
                  border: `1.5px solid ${CARD_STYLES[idx].border}`,
                  boxShadow:'0 2px 8px rgba(0,0,0,0.04)',
                  padding:'14px 14px 10px',
                  display:'flex', flexDirection:'column', gap:10,
                  transition:'box-shadow 0.2s, transform 0.2s',
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.boxShadow = '0 6px 20px rgba(0,0,0,0.1)';
                  e.currentTarget.style.transform = 'translateY(-2px)';
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.04)';
                  e.currentTarget.style.transform = 'translateY(0)';
                }}
              >
                {/* Card header */}
                <div style={{
                  display:'flex', justifyContent:'space-between', alignItems:'center'
                }}>
                  <div style={{display:'flex', alignItems:'center', gap:6}}>
                    <span style={{
                      fontSize:16, color: CARD_STYLES[idx].accent
                    }}>
                      {chart.icon}
                    </span>
                    <span style={{
                      fontSize:11, fontWeight:700, color:'#374151',
                      textTransform:'uppercase', letterSpacing:'0.06em'
                    }}>
                      {chart.label}
                    </span>
                  </div>
                  <div style={{display:'flex', gap:6}}>
                    <button onClick={() => downloadChart(chart.id)} style={{
                      fontSize:10, color:'#9ca3af', background:'#f9fafb',
                      border:'1px solid #f3f4f6', borderRadius:5,
                      padding:'3px 8px', cursor:'pointer'
                    }}>
                      ⬇
                    </button>
                    <button onClick={() => setFocused(chart.id)} style={{
                      fontSize:10, color: CARD_STYLES[idx].accent,
                      background: `${CARD_STYLES[idx].border}`,
                      border:'none', borderRadius:5,
                      padding:'3px 8px', cursor:'pointer', fontWeight:700
                    }}>
                      Focus ⤢
                    </button>
                  </div>
                </div>

                {/* Chart */}
                <ResponsiveContainer width="100%" height={210}>
                  {chart.render()}
                </ResponsiveContainer>
              </div>
            ))}
          </div>

          {/* ── Summary Stats full width ── */}
          <div style={{
            marginTop: 14, background:'#fff', borderRadius:12,
            border:'1.5px solid #e5e7eb',
            boxShadow:'0 2px 8px rgba(0,0,0,0.04)',
            overflow:'hidden'
          }}>
            <div style={{
              padding:'12px 20px',
              borderBottom:'1px solid #f3f4f6',
              display:'flex', justifyContent:'space-between', alignItems:'center'
            }}>
              <span style={{
                fontSize:11, fontWeight:700, color:'#374151',
                textTransform:'uppercase', letterSpacing:'0.06em'
              }}>
                📊 Summary Statistics
              </span>
              <span style={{fontSize:11, color:'#9ca3af'}}>
                {data.length} rows · {numCols.length} numeric column{numCols.length !== 1 ? 's' : ''}
              </span>
            </div>
            {renderStats()}
          </div>
        </div>
      )}
    </div>
  );
}
/* ── EdaPanel ─────────────────────────────────────────────────── */
function EdaPanel({ profile, edaInsights }) {
  const eda  = edaInsights || {};
  const cols = normalizeCols(profile);

  return (
    <div className="eda-panel">
      {eda.headline && (
        <div className="eda-headline">
          <div className="eda-headline-label">Gemini Analysis</div>
          <div className="eda-headline-text">{safeStr(eda.headline)}</div>
        </div>
      )}

      {Array.isArray(eda.key_findings) && eda.key_findings.length > 0 && (
        <div className="eda-grid">
          <div className="eda-box">
            <div className="eda-box-title">Key Findings</div>
            {eda.key_findings.map((f,i) => (
              <div key={i} className="eda-finding">
                <span className="eda-num">{i+1}</span>{safeStr(f)}
              </div>
            ))}
          </div>
          {eda.data_quality && (
            <div className="eda-box">
              <div className="eda-box-title">Data Quality</div>
              <div className="eda-dq-score">
                <span className="eda-dq-num">{eda.data_quality.score ?? '--'}</span>
                <span className="eda-dq-label">/ 100</span>
              </div>
              <div className={`eda-dq-verdict ${(eda.data_quality.score ?? 0) >= 70 ? 'good' : 'warn'}`}>
                {safeStr(eda.data_quality.verdict)}
              </div>
              {Array.isArray(eda.data_quality.issues) && eda.data_quality.issues.map((iss,i) => (
                <div key={i} className="eda-issue">Warning: {safeStr(iss)}</div>
              ))}
            </div>
          )}
          {Array.isArray(eda.recommendations) && eda.recommendations.length > 0 && (
            <div className="eda-box">
              <div className="eda-box-title">Recommendations</div>
              {eda.recommendations.map((r,i) => (
                <div key={i} className="eda-rec">Tip: {safeStr(r)}</div>
              ))}
            </div>
          )}
        </div>
      )}

      {cols.length > 0 && (
        <div className="eda-cols-section">
          <div className="eda-cols-title">Column Profiles</div>
          <div className="eda-cols-grid">
            {cols.map((col, idx) => {
              const colType = col.type ?? col.dtype ?? (col.mean !== undefined ? 'numeric' : 'categorical');
              const topVals = normalizeTopValues(col.top_values ?? col.top_counts);
              return (
                <div key={col.name ?? idx} className="eda-col-card">
                  <div className="eda-col-header">
                    <span className="eda-col-name">{col.name ?? `col_${idx}`}</span>
                    <Badge color={colType === 'numeric' ? 'blue' : 'gray'} size="sm">{colType}</Badge>
                  </div>
                  {colType === 'numeric' ? (
                    <div className="eda-col-stats">
                      <div className="eda-stat"><span>Min</span><strong>{col.min ?? '--'}</strong></div>
                      <div className="eda-stat"><span>Max</span><strong>{col.max ?? '--'}</strong></div>
                      <div className="eda-stat"><span>Mean</span><strong>{col.mean != null ? Number(col.mean).toFixed(2) : '--'}</strong></div>
                      <div className="eda-stat"><span>Nulls</span><strong>{col.null_pct != null ? `${Number(col.null_pct).toFixed(1)}%` : '--'}</strong></div>
                    </div>
                  ) : (
                    <div className="eda-col-top">
                      {topVals.slice(0,5).map(([v,c],i) => (
                        <div key={i} className="eda-top-item">
                          <span className="eda-top-val">{v}</span>
                          <span className="eda-top-count">{c}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {cols.length === 0 && !eda.headline && (
        <div style={{padding:'32px',textAlign:'center',color:'var(--gray-400)',fontSize:'0.875rem'}}>
          No EDA profile available for this result.
        </div>
      )}
    </div>
  );
}

/* ── GenUIPanel ───────────────────────────────────────────────── */
function GenUIPanel({ result, question }) {
  const [html, setHtml]       = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState(null);

  const generate = async () => {
    setLoading(true);
    setError(null);
    try {
      const rows    = result.data    || [];
      const columns = result.columns || Object.keys(rows[0] || {});
      const res = await genuiAPI.generate({ question, columns, rows });
      setHtml(res.data.html);
    } catch (e) {
      setError(e.response?.data?.detail || 'Failed to generate UI');
    } finally {
      setLoading(false);
    }
  };

  if (!html && !loading) return (
    <div style={{ padding: '40px', textAlign: 'center' }}>
      <p style={{ color: 'var(--gray-500)', marginBottom: '16px', fontSize: '0.9rem' }}>
        Gemini will generate an interactive visualization app from your data.
      </p>
      <button onClick={generate} className="sql-toggle" style={{ margin: '0 auto' }}>
        <Layers size={14}/> Generate Live UI
      </button>
    </div>
  );

  if (loading) return (
    <div style={{ padding: '60px', textAlign: 'center', color: 'var(--gray-400)' }}>
      <div style={{ fontSize: '1.5rem', marginBottom: '12px' }}>⚙️</div>
      <div style={{ fontWeight: 600, marginBottom: '8px', color: 'var(--gray-600)', fontSize: '0.95rem' }}>
        Generating interactive UI...
      </div>
      <div style={{ fontSize: '0.82rem', color: 'var(--gray-400)' }}>
        Gemini is building a custom app for your data.<br/>This takes 10–20 seconds.
      </div>
    </div>
  );

  if (error) return (
    <div style={{ padding: '24px', color: 'red', fontSize: '0.85rem' }}>{error}</div>
  );

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '8px' }}>
        <button onClick={generate} className="sql-toggle">
          ↻ Regenerate
        </button>
      </div>
      <iframe
        srcDoc={html}
        style={{ width: '100%', height: '600px', border: 'none', borderRadius: '8px' }}
        sandbox="allow-scripts"
        title="Generative UI"
      />
    </div>
  );
}

/* ── ResultsPanel (main export) ───────────────────────────────── */
export default function ResultsPanel({ result, sql, question }) {
  const [tab, setTab]         = useState('table');
  const [showSql, setShowSql] = useState(false);
  const [aiRows, setAiRows]   = useState(null);

  if (!result) return null;

  const data    = result.data    || [];
  // Use aiRows columns if available (ai.generate adds new columns)
  const columns = aiRows
    ? Object.keys(aiRows[0] || {})
    : (result.columns || []);

  const tabs = [
    { id: 'table',  label: 'Table',        icon: <Table2 size={14}/>    },
    { id: 'chart',  label: 'Charts',       icon: <BarChart2 size={14}/> },
    { id: 'eda',    label: 'EDA Profile',  icon: <Brain size={14}/>     },
    { id: 'liveui', label: 'Live UI',      icon: <Layers size={14}/>    },
    { id: 'ai',     label: 'AI Functions', icon: <Sparkles size={14}/>  },
  ];

  return (
    <div className="results-panel fade-in">
      <div className="results-meta">
        <div className="results-meta-left">
          <Badge color="green">{data.length} rows</Badge>
          {result.execution_time_ms && <Badge color="gray">{result.execution_time_ms}ms</Badge>}
          {Array.isArray(result.tables_used) && result.tables_used.length > 0 && (
            <Badge color="blue">{result.tables_used.join(', ')}</Badge>
          )}
          {result.collection && <Badge color="green">{result.collection}</Badge>}
        </div>
        {(sql || result.sql) && (
          <button className="sql-toggle" onClick={() => setShowSql(s => !s)}>
            <Code2 size={14}/> SQL {showSql ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
          </button>
        )}
      </div>

      {showSql && (sql || result.sql) && (
        <div className="sql-drawer">
          <pre className="sql-code">{sql || result.sql}</pre>
        </div>
      )}

      {result.summary && (
        <div className="results-summary">{safeStr(result.summary)}</div>
      )}

      <Tabs tabs={tabs} active={tab} onChange={setTab} />

      <div className="results-body">
        {/* ✅ Uses aiRows when AI function has run, otherwise original data */}
        {tab === 'table'  && <DataTable data={aiRows || data} columns={columns} />}
        {tab === 'chart'  && <ChartPanel data={data} viz={result.viz} summary={result.summary} />}
        {tab === 'eda'    && <EdaPanel profile={result.profile} edaInsights={result.eda_insights} />}
        {tab === 'liveui' && <GenUIPanel result={result} question={question} />}
        {tab === 'ai'     && (
          <AiFunctionsPanel
            data={data}
            onResult={(enriched) => setAiRows(enriched)}
          />
        )}
      </div>
    </div>
  );
}
